#include <bits/stdc++.h>
using namespace std;

vector<vector<int>> findTopK(vector<int>& arr, int n, int k) {
    vector<vector<int>> result;
    map<int, int> freq;

    for(int i = 0; i < n; i++) {
        freq[arr[i]]++;

        vector<pair<int, int>> temp;
        for(auto it : freq) {
            temp.push_back({it.second, -it.first});
        }

        sort(temp.begin(), temp.end(), greater<pair<int, int>>());

        vector<int> current;
        for(int j = 0; j < min(k, (int)temp.size()); j++) {
            current.push_back(-temp[j].second);
        }

        result.push_back(current);
    }

    return result;
}

int main() {
    int n, k;
    cin >> n >> k;

    vector<int> arr(n);
    for(int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    vector<vector<int>> result = findTopK(arr, n, k);

    for(const auto& v : result) {
        for(int num : v) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}

