#include <stdio.h>
#include <stdlib.h>

#define MAX 10000

// Structure to store (frequency, -value)
typedef struct {
    int freq;
    int val;
} Pair;

// Comparator for sorting (descending by freq, then ascending by value)
int compare(const void *a, const void *b) {
    Pair *p1 = (Pair *)a;
    Pair *p2 = (Pair *)b;

    if (p2->freq != p1->freq)
        return p2->freq - p1->freq; // higher freq first
    return p1->val - p2->val;       // smaller value first
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    int arr[MAX];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    int freq[MAX] = {0};   // frequency array (assuming values are small)

    for (int i = 0; i < n; i++) {
        freq[arr[i]]++;

        // Build temp array
        Pair temp[MAX];
        int size = 0;

        for (int j = 0; j < MAX; j++) {
            if (freq[j] > 0) {
                temp[size].freq = freq[j];
                temp[size].val = j;
                size++;
            }
        }

        // Sort temp array
        qsort(temp, size, sizeof(Pair), compare);

        // Print top k elements
        int limit = (k < size) ? k : size;
        for (int j = 0; j < limit; j++) {
            printf("%d ", temp[j].val);
        }
        printf("\n");
    }

    return 0;
}

